import React from "react";
import Sidebar from "./components/Sidebar";
import LoginBox from "./components/LoginBox"; // Import LoginBox
import { FaProjectDiagram } from "react-icons/fa"; // Importing an icon

const AppLayout = ({ children }) => {
  return (
    <div className="flex h-screen bg-gray-100">
      {/* Sidebar */}
      <aside className="w-50 bg-gray-900 text-white p-4">
        <Sidebar />
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col justify-center items-center">
        {/* Header */}
        <header className="bg-gradient-to-r from-purple-700 to-indigo-800 text-white py-6 px-8 shadow-lg w-full text-center flex items-center justify-center space-x-4">
          <FaProjectDiagram className="text-4xl text-yellow-300" />
          <h1 className="text-3xl font-bold tracking-wide flex items-center space-x-2">
            <span>🚀 Manage Your Projects Efficiently with</span> 
            <span className="text-yellow-300">Proma</span> 
          </h1>
        </header>

        {/* Page Content */}
        <div className="p-6">{children}</div>

        {/* Login Box in Center */}
        <LoginBox />
      </main>
    </div>
  );
};

export default AppLayout;
